export const Hero = () => (
    <section style={{ padding: '100px 20px', textAlign: 'center', background: '#0c0a09', color: '#fff' }}>
        <h1 style={{ fontSize: '4rem', fontWeight: '900' }}>Mastering Your <span style={{ color: '#ea580c' }}>Digital Needs.</span></h1>
        <p style={{ fontSize: '1.5rem', color: '#a3a3a3', maxWidth: '700px', margin: '20px auto' }}>
            Solusi IT On-Demand tercepat untuk masalah hardware, software, dan jaringan. Kami datang, kami perbaiki.
        </p>
        <button style={{ padding: '15px 40px', background: '#ea580c', borderRadius: '12px', color: '#fff', border: 'none', cursor: 'pointer' }}>Mulai Pesanan</button>
    </section>
);
